import{_ as t,c as a,o as r,ag as i}from"./chunks/framework.D4Vqf8I7.js";const u=JSON.parse('{"title":"The UNIX Pipe Card Game","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/games/board/pipes.md","filePath":"docs/wi/games/board/pipes.md","lastUpdated":1784041112000}'),p={name:"docs/wi/games/board/pipes.md"};function o(s,e,n,l,g,c){return r(),a("div",null,e[0]||(e[0]=[i('<h1 id="the-unix-pipe-card-game" tabindex="-1">The UNIX Pipe Card Game <a class="header-anchor" href="#the-unix-pipe-card-game" aria-label="Permalink to &quot;The UNIX Pipe Card Game&quot;">​</a></h1><p>punkx.org/unix-pipe-game/</p><p>Это карточная игра для обучения детей комбинированию unix-команд через <mark>конвейеры (pipes)</mark>.</p><p>Игра предполагает, что родитель знает основные unix-команды: <code>cat, grep, tail, head, wc, sort, uniq</code>. Родитель также должен показать эти команды в действии на компьютере. Если у вас нет UNIX-системы, вы можете использовать <a href="https://bellard.org/jslinux/vm.html?url=alpine-x86.cfg&amp;mem=192" target="_blank" rel="noreferrer">jslinux</a> в вашем браузере.</p><p><img src="https://punkx.org/unix-pipe-game/photos/deck.jpg" alt="Deck"></p><ul><li>распечатайте сами: <a href="unix-pipe-cards.pdf">unix-pipe-cards.pdf</a>, <a href="unix-pipe-box.pdf">unix-pipe-box.pdf</a></li><li>код: <a href="https://github.com/jackdoe/programming-for-kids/tree/master/projects/unix-pipe-game" target="_blank" rel="noreferrer">unix-pipe-game</a></li><li>автор: <a href="https://github.com/jackdoe" target="_blank" rel="noreferrer">github.com/jackdoe</a></li><li>соавтор: <a href="https://punkjazz.org/jackie" target="_blank" rel="noreferrer">Jackie</a></li><li>контакт: <a href="mailto:b0000@fastmail.com" target="_blank" rel="noreferrer">b0000@fastmail.com</a></li><li>лицензия: CC BY 4.0</li></ul><p>Если вы хотите сыграть в <strong>более сложную</strong> версию, вы также можете получить дополнение: <a href="https://punkx.org/unix-pipe-game/ext-0.1/index.html" target="_blank" rel="noreferrer">UNIX Pipe Game - Process Substitution</a></p><hr><p><strong>Пример игрового раунда:</strong></p><p><strong>Задача:</strong> <strong>напечатать наиболее часто встречающуюся строку из файла</strong>. Сначала нужно сделать cat файла (в нашем случае файл — это card 03.txt), затем отсортировать его, посчитать уникальные строки, затем сделать числовую сортировку, затем tail -1:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cat 03.txt | sort | uniq -c | sort -n | tail -1</span></span></code></pre></div><p><img src="https://punkx.org/unix-pipe-game/photos/example.jpg" alt="Example"></p><hr><h2 id="правила" tabindex="-1">ПРАВИЛА: <a class="header-anchor" href="#правила" aria-label="Permalink to &quot;ПРАВИЛА:&quot;">​</a></h2><blockquote><p><strong>0.</strong> Самый молодой игрок выбирает один из двух форматов игры:</p><ul><li>Тот, у кого <strong>наименьшая</strong> цепочка конвейера для выполнения задачи, выигрывает раунд.</li><li>Тот, у кого <strong>наибольшая</strong> цепочка конвейера для выполнения задачи, выигрывает раунд.</li></ul><p><strong>1.</strong> Самый молодой игрок выбирает задачу из карты задач. Нельзя выбирать одну и ту же задачу дважды.</p><p><strong>2.</strong> Перемешайте карты.</p><p><strong>3.</strong> Положите карты рубашкой вверх на стол.</p><p><strong>4.</strong> По часовой стрелке каждый игрок берет верхнюю карту из колоды и пытается выполнить задачу.</p><p><strong>5.</strong> Первый игрок, выполнивший задачу, получает очко.</p><p><strong>6.</strong> <strong>ЕСЛИ</strong> задач больше нет, <strong>ПЕРЕЙТИ</strong> к шагу 8</p><p><strong>7.</strong> <strong>ПЕРЕЙТИ</strong> к шагу 1.</p><p><strong>8.</strong> ИГРА ОКОНЧЕНА. ВСТАВЬТЕ МОНЕТУ. <strong>ПЕРЕЙТИ</strong> к шагу 8</p></blockquote><h2 id="задачи" tabindex="-1">ЗАДАЧИ <a class="header-anchor" href="#задачи" aria-label="Permalink to &quot;ЗАДАЧИ&quot;">​</a></h2><ul><li>напечатать вторую строку</li><li>напечатать предпоследнюю строку</li><li>напечатать 7-ю строку</li><li>напечатать наиболее часто встречающуюся строку</li><li>напечатать наименее часто встречающуюся строку</li><li>посчитать, сколько строк содержат &quot;rises&quot;</li><li>напечатать первую строку, содержащую W</li><li>посчитать строки, содержащие &quot;in&quot;</li><li>показать две случайные строки</li><li>посчитать слова в последних двух строках</li><li>напечатать 7-ю и 8-ю строки</li><li>посчитать строки с !</li><li>посчитать строки без !</li><li>создать цепочку команд, которая ничего не печатает</li></ul><hr><p>Вот как выглядят колоды карт:</p><p><img src="https://punkx.org/unix-pipe-game/photos/many-decks.jpg" alt="Many decks"></p>',20)]))}const h=t(p,[["render",o]]);export{u as __pageData,h as default};
